const s=`{% block sw_cms_visibility_toggle %} <div class="sw-cms-visibility-toggle-wrapper"> <div class="sw-cms-visibility-toggle"> <mt-icon name="regular-eye-slash" size="24" /> <span class="sw-cms-visibility-toggle__text">{{ $t('sw-cms.detail.label.visibilityParagraph') }}</span> <button class="sw-cms-visibility-toggle__button" @click="$emit('toggle')" > <span>{{ text }}</span> <mt-icon :name="isCollapsed ? 'regular-chevron-down-xs' : 'regular-chevron-up-xs'" size="10" /> </button> </div> </div> {% endblock %}`,e={template:s,props:{text:{type:String,required:!0},isCollapsed:{type:Boolean,required:!0}}};export{e as default};
